function report = runPaperStudyAssessment(options)
%RUNPAPERSTUDYASSESSMENT Execute the single frozen P2 held-out assessment.
%
% Each scene is rendered once, then receives the frozen sparse settings and
% bounded dense WTA/SGM evaluation. Scene-level pairing, bootstrap intervals,
% Holm correction, strata, and direction classifications come only from the
% committed assessment policy. Traceability: algo/main.tex Sec. 10.6 and the
% RD1--RD4 decision boxes; implementation plan P2 step 4; D067.

arguments
    options.StudyFile (1, 1) string = ...
        PaperStudyContract.defaultStudyFile
    options.OutcomeIdentifier (1, 1) string = "paper_study_heldout_v1"
    options.OutputFile (1, 1) string = ""
    options.FullReportFile (1, 1) string = ""
    options.SourceImplementationCommit (1, 1) string = ""
    options.WorkingPrecision (1, 1) string ...
        {mustBeMember(options.WorkingPrecision, ...
        ["single", "double"])} = "single"
    options.RetainCaseProducts (1, 1) logical = true
    options.UseParallel (1, 1) logical = true
    options.NumWorkers (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
    options.Verbose (1, 1) logical = true
end

root = fileparts(fileparts(mfilename("fullpath")));
oldPath = path;
addpath(fullfile(root, "src"));
cleanup = onCleanup(@() path(oldPath));
contract = PaperStudyContract(options.StudyFile);
if contract.State ~= "policy-frozen" ...
        || ~isfield(contract.Manifest, "assessmentPolicy")
    error("runPaperStudyAssessment:PolicyNotFrozen", ...
        "Held-out assessment requires a committed assessment policy.");
end
if options.OutcomeIdentifier ~= ...
        string(contract.Manifest.assessmentPolicy.identifier)
    error("runPaperStudyAssessment:OutcomeIdentifierMismatch", ...
        "OutcomeIdentifier must equal the frozen assessment identifier.");
end
if isfield(contract.Manifest, "heldoutOutcome")
    error("runPaperStudyAssessment:HeldoutAlreadyComplete", ...
        "The committed manifest already records the single held-out run.");
end
if options.OutputFile == ""
    options.OutputFile = string(fullfile(root, "outputs", ...
        options.OutcomeIdentifier + ".json"));
end
if isfile(options.OutputFile)
    error("runPaperStudyAssessment:OutcomeAlreadyExists", ...
        "Refusing to overwrite existing held-out outcome '%s'.", ...
        options.OutputFile);
end
if options.FullReportFile ~= "" && isfile(options.FullReportFile)
    error("runPaperStudyAssessment:OutcomeAlreadyExists", ...
        "Refusing to overwrite existing held-out report '%s'.", ...
        options.FullReportFile);
end

% This is the sole call that crosses the committed held-out row boundary.
cases = contract.heldoutCases;
n = height(cases);
caseResult = cell(n, 1);
manifest = contract.Manifest;
precision = options.WorkingPrecision;
timer = tic;
if options.UseParallel
    [pool, workers] = threadPool(options.NumWorkers);
    if options.Verbose
        fprintf("P2 held-out assessment: %d cases on %d thread workers\n", ...
            n, workers);
    end
    parfor (k = 1:n, workers)
        caseResult{k} = evaluateCase(cases(k, :), manifest, precision);
    end
    execution = "parallel cases on parpool('threads')";
    poolClass = string(class(pool));
else
    workers = 1;
    poolClass = "none";
    for k = 1:n
        if options.Verbose
            fprintf("P2 held-out %d/%d: %s\n", ...
                k, n, cases.Identifier(k));
        end
        caseResult{k} = evaluateCase(cases(k, :), manifest, precision);
    end
    execution = "serial cases";
end
totalSeconds = toc(timer);

[sparseSummary, denseSummary, scaleGroups, direction, runtime, ...
    caseTiming] = assemble(caseResult, cases);
comparisons = comparisonTable(manifest.assessmentPolicy.primaryComparisons);
statistics = PaperStudySceneStatistics.evaluate( ...
    sparseSummary, comparisons, manifest, ...
    RetainBootstrapSamples=true);
denseComparison = denseComparisons(denseSummary, ...
    manifest.assessmentPolicy.denseAssessment.comparisons);
decisions = directionDecisions(statistics.Comparisons, ...
    sparseSummary, direction, runtime, manifest);

artifact = struct( ...
    "identifier", options.OutcomeIdentifier, ...
    "sourceStudyIdentifier", contract.Identifier, ...
    "sourceImplementationCommit", options.SourceImplementationCommit, ...
    "state", "heldout-complete", ...
    "valid", true, ...
    "caseIdentifiers", cases.Identifier.', ...
    "heldoutAccessed", true, ...
    "heldoutRunOrdinal", 1, ...
    "workingPrecision", options.WorkingPrecision, ...
    "execution", execution, ...
    "numWorkers", workers, ...
    "caseTiming", table2struct(caseTiming), ...
    "totalSeconds", totalSeconds, ...
    "sparseSummary", table2struct(sparseSummary), ...
    "denseSummary", table2struct(denseSummary), ...
    "denseScaleGroups", table2struct(scaleGroups), ...
    "primaryStatistics", table2struct(statistics.Comparisons), ...
    "denseComparisons", table2struct(denseComparison), ...
    "directionDiagnostics", table2struct(direction), ...
    "researchDirectionRuntime", table2struct(runtime), ...
    "researchDirectionDecisions", table2struct(decisions), ...
    "statisticsDefinition", struct( ...
    "bootstrapReplicates", statistics.BootstrapReplicates, ...
    "bootstrapSeed", statistics.BootstrapSeed, ...
    "confidenceLevel", statistics.ConfidenceLevel, ...
    "correction", statistics.Correction, ...
    "resamplingUnit", statistics.ResamplingUnit, ...
    "pixelInference", statistics.PixelInference), ...
    "assessmentPolicy", manifest.assessmentPolicy);
report = struct( ...
    "StudyIdentifier", contract.Identifier, ...
    "StudyState", contract.State, ...
    "CaseIdentifiers", cases.Identifier.', ...
    "SparseSummary", sparseSummary, ...
    "DenseSummary", denseSummary, ...
    "DenseScaleGroups", scaleGroups, ...
    "Statistics", statistics, ...
    "DenseComparisons", denseComparison, ...
    "DirectionDiagnostics", direction, ...
    "ResearchDirectionRuntime", runtime, ...
    "ResearchDirectionDecisions", decisions, ...
    "CaseResults", {caseResult}, ...
    "CaseProductsRetained", options.RetainCaseProducts, ...
    "HeldoutAccessed", true, ...
    "Execution", execution, ...
    "PoolClass", poolClass, ...
    "NumWorkers", workers, ...
    "CaseTiming", caseTiming, ...
    "TotalSeconds", totalSeconds, ...
    "SummaryArtifact", artifact);
if ~options.RetainCaseProducts
    report.CaseResults = cell(0, 1);
end
folder = string(fileparts(options.OutputFile));
if strlength(folder) > 0 && ~isfolder(folder)
    mkdir(folder);
end
writelines(jsonencode(artifact, PrettyPrint=true), options.OutputFile);
if options.FullReportFile ~= ""
    folder = string(fileparts(options.FullReportFile));
    if strlength(folder) > 0 && ~isfolder(folder)
        mkdir(folder);
    end
    save(options.FullReportFile, "report", "-v7.3");
end
if options.Verbose
    fprintf("P2 held-out complete: %d cases, %.3f s\n", n, totalSeconds);
    disp(statistics.Comparisons(:, ["Direction", "Candidate", ...
        "Baseline", "RelativeImprovement", ...
        "HolmCorrectedLowerRelativeImprovement", ...
        "PassesCommonPromotion"]));
    disp(decisions(:, ["Direction", "Classification"]));
    fprintf("Compact outcome: %s\n", options.OutputFile);
end
clear cleanup
end

function out = evaluateCase(caseRow, manifest, precision)
c = PaperStudySyntheticCase(caseRow, manifest);
r = c.render(WorkingPrecision=precision);
sparse = PaperStudySelectedSparseEvaluator(manifest).evaluate(r);
dense = PaperStudyDenseEvaluator(manifest).evaluate(r, ...
    RetainCostVolumes=false, ProfileResearchRuntime=true);
out = struct("Sparse", sparse, "Dense", dense, ...
    "RenderSeconds", r.RenderSeconds, ...
    "TotalSeconds", sparse.TotalSeconds + dense.TotalSeconds);
end

function [sparse, dense, groups, direction, runtime, timing] = ...
        assemble(results, cases)
n = numel(results);
sp = cell(n, 1);
dp = cell(n, 1);
gp = cell(n, 1);
xp = cell(n, 1);
rp = cell(n, 1);
renderSeconds = zeros(n, 1);
sparseSeconds = zeros(n, 1);
denseSeconds = zeros(n, 1);
totalSeconds = zeros(n, 1);
for k = 1:n
    sp{k} = addFactors(results{k}.Sparse.Summary, cases, k);
    dp{k} = addFactors(results{k}.Dense.Summary, cases, k);
    gp{k} = results{k}.Dense.ScaleGroups;
    gp{k}.Case = repmat(cases.Identifier(k), height(gp{k}), 1);
    xp{k} = struct2table(results{k}.Sparse.DirectionDiagnostics, ...
        AsArray=true);
    xp{k}.Case = cases.Identifier(k);
    rp{k} = struct2table( ...
        results{k}.Dense.ResearchDirection3Runtime, AsArray=true);
    rp{k}.Case = cases.Identifier(k);
    renderSeconds(k) = results{k}.RenderSeconds;
    sparseSeconds(k) = results{k}.Sparse.TotalSeconds;
    denseSeconds(k) = results{k}.Dense.TotalSeconds;
    totalSeconds(k) = results{k}.TotalSeconds;
end
sparse = vertcat(sp{:});
dense = vertcat(dp{:});
groups = vertcat(gp{:});
direction = vertcat(xp{:});
runtime = vertcat(rp{:});
timing = table(cases.Identifier, renderSeconds, sparseSeconds, ...
    denseSeconds, totalSeconds, VariableNames=["Case", ...
    "RenderSeconds", "SparseSeconds", "DenseSeconds", "TotalSeconds"]);
end

function t = addFactors(t, cases, k)
n = height(t);
t.Case = repmat(cases.Identifier(k), n, 1);
t.Surface = repmat(cases.Surface(k), n, 1);
t.Texture = repmat(cases.Texture(k), n, 1);
t.ConvergenceDegrees = repmat(cases.ConvergenceDegrees(k), n, 1);
t.ObliquityDegrees = repmat(cases.ObliquityDegrees(k), n, 1);
t.Radiometry = repmat(cases.Radiometry(k), n, 1);
t.CameraBias = repmat(cases.CameraBias(k), n, 1);
end

function t = comparisonTable(s)
t = table(string({s.direction}).', string({s.candidate}).', ...
    string({s.baseline}).', string({s.stage}).', ...
    string({s.definition}).', VariableNames=["Direction", "Candidate", ...
    "Baseline", "Stage", "Definition"]);
end

function out = denseComparisons(summary, policy)
rows = cell(2 .* numel(policy), 1);
k = 0;
for j = 1:numel(policy)
    for stage = string(policy(j).stages).'
        k = k + 1;
        rows{k} = pairedRow(summary, string(policy(j).direction), ...
            string(policy(j).candidate), string(policy(j).baseline), stage);
    end
end
out = vertcat(rows{:});
end

function row = pairedRow(summary, direction, candidate, baseline, stage)
c = summary(summary.Method == candidate & summary.Stage == stage, :);
b = summary(summary.Method == baseline & summary.Stage == stage, :);
[~, ic, ib] = intersect(c.Case, b.Case, "stable");
ce = c.EndpointEpeRmsePixels(ic);
be = b.EndpointEpeRmsePixels(ib);
cc = c.Coverage(ic);
bc = b.Coverage(ib);
row = table(direction, candidate, baseline, stage, numel(ce), ...
    mean(ce), mean(be), 1 - mean(ce) ./ mean(be), mean(be - ce), ...
    mean(ce < be), mean(bc - cc), max(ce - be), ...
    VariableNames=["Direction", "Candidate", "Baseline", "Stage", ...
    "SceneCount", "CandidateMeanEpePixels", "BaselineMeanEpePixels", ...
    "RelativeImprovement", "MeanPairedImprovementPixels", ...
    "ImprovedSceneFraction", "MeanCoverageLoss", ...
    "MaximumSceneEpeIncreasePixels"]);
end

function out = directionDecisions(primary, sparse, diagnostic, runtime, policy)
a = policy.acceptance;
p = policy.assessmentPolicy;
rd1Primary = primary.PassesCommonPromotion(primary.Direction == "RD1");
high = diagnostic.HighDeformation;
rd1Metric = mean(diagnostic.T3TruthCostRelativeReduction(high), "omitnan");
rd1Threshold = a.researchDirection1. ...
    minimumHighDeformationTransportErrorReduction;
rd1Gate = isfinite(rd1Metric) && rd1Metric >= rd1Threshold;

rd2Primary = primary.PassesCommonPromotion(primary.Direction == "RD2");
rd2Metric = mean(diagnostic.WidelyLinearPhysicalValidFraction, "omitnan");
rd2Gate = p.researchDirection2.controlledAppliedDiagnosticPass;

normal = sparse.Radiometry ~= ...
    string(p.researchDirection3.polarityReversedRadiometry);
reversed = ~normal;
rd3Normal = regimeImprovement(sparse, normal, ...
    "MultiHarmonicGated", "T3");
rd3Reversed = regimeImprovement(sparse, reversed, ...
    "MultiHarmonicGated", "T3");
rd3Runtime = mean(runtime.MultiHarmonicToT3Ratio, "omitnan");
rd3Threshold = a.researchDirection3. ...
    minimumNormalAndReversedRegimeRelativeImprovement;
rd3RuntimeThreshold = a.researchDirection3.maximumRuntimeRatioToT3;
rd3Gate = rd3Normal >= rd3Threshold && rd3Reversed >= rd3Threshold ...
    && rd3Runtime <= rd3RuntimeThreshold;
rd3Primary = primary.PassesCommonPromotion(primary.Direction == "RD3");

noise = diagnostic.Radiometry == ...
    string(p.researchDirection4.moderateNoiseRadiometry);
rd4Rotation = mean( ...
    diagnostic.ComplexLogRotationBiasDegrees(noise), "omitnan");
rd4Gain = mean(diagnostic.ComplexLogLogGainBias(noise), "omitnan");
rd4RotationThreshold = a.researchDirection4. ...
    maximumModerateNoiseRotationBiasDegrees;
rd4GainThreshold = a.researchDirection4.maximumModerateNoiseLogGainBias;
rd4Gate = rd4Rotation <= rd4RotationThreshold ...
    && rd4Gain <= rd4GainThreshold;
rd4Primary = primary.PassesCommonPromotion(primary.Direction == "RD4");

classification = strings(4, 1);
classification(1) = choose(rd1Primary && rd1Gate, ...
    "accepted", "rejected");
classification(2) = "diagnostic-only";
classification(3) = choose(rd3Primary && rd3Gate, ...
    "diagnostic-only", "rejected");
classification(4) = choose(rd4Primary && rd4Gate, "accepted", ...
    choose(rd4Gate, "diagnostic-only", "rejected"));
out = table(["RD1"; "RD2"; "RD3"; "RD4"], ...
    [rd1Primary; rd2Primary; rd3Primary; rd4Primary], ...
    [rd1Gate; rd2Gate; rd3Gate; rd4Gate], ...
    [true; false; false; true], classification, ...
    ["High-deformation T3 truth-cost reduction"; ...
    "Widely-linear physical-valid fraction"; ...
    "Normal-regime endpoint improvement"; ...
    "Moderate-noise rotation bias degrees"], ...
    [rd1Metric; rd2Metric; rd3Normal; rd4Rotation], ...
    [rd1Threshold; NaN; rd3Threshold; rd4RotationThreshold], ...
    [rd1Gate; isfinite(rd2Metric); rd3Normal >= rd3Threshold; ...
    rd4Rotation <= rd4RotationThreshold], ...
    ["Common raw endpoint promotion"; ...
    "Controlled applied diagnostic pass (D027)"; ...
    "Reversed-regime endpoint improvement"; ...
    "Moderate-noise absolute log-gain bias"], ...
    [double(rd1Primary); double(rd2Gate); rd3Reversed; rd4Gain], ...
    [1; 1; rd3Threshold; rd4GainThreshold], ...
    [rd1Primary; rd2Gate; rd3Reversed >= rd3Threshold; ...
    rd4Gain <= rd4GainThreshold], ...
    ["T3 versus T0 is the primary Holm-family comparison"; ...
    string(p.researchDirection2.interpretation); ...
    "known-factor gate cannot become a deployable default"; ...
    "matching acceptance also requires the common endpoint gate"], ...
    VariableNames=["Direction", "PrimaryComparisonPass", ...
    "DirectionSpecificPass", "Deployable", "Classification", ...
    "Metric1Name", "Metric1Value", "Metric1Threshold", ...
    "Metric1Pass", "Metric2Name", "Metric2Value", ...
    "Metric2Threshold", "Metric2Pass", "Notes"]);
out.Metric3Name = [""; ""; "Multi-harmonic/T3 runtime ratio"; ""];
out.Metric3Value = [NaN; NaN; rd3Runtime; NaN];
out.Metric3Threshold = [NaN; NaN; rd3RuntimeThreshold; NaN];
out.Metric3Pass = [true; true; rd3Runtime <= rd3RuntimeThreshold; true];
end

function value = regimeImprovement(summary, rows, candidate, baseline)
c = summary(rows & summary.Method == candidate, :);
b = summary(rows & summary.Method == baseline, :);
[~, ic, ib] = intersect(c.Case, b.Case, "stable");
value = 1 - mean(c.EndpointEpeRmsePixels(ic)) ...
    ./ mean(b.EndpointEpeRmsePixels(ib));
end

function out = choose(condition, yes, no)
if condition
    out = string(yes);
else
    out = string(no);
end
end

function [pool, n] = threadPool(requested)
pool = gcp("nocreate");
if isempty(pool)
    pool = parpool("threads");
end
if ~isa(pool, "parallel.ThreadPool")
    error("runPaperStudyAssessment:ThreadPoolRequired", ...
        "Held-out assessment requires parpool('threads').");
end
if requested == 0
    n = pool.NumWorkers;
else
    n = requested;
end
if n > pool.NumWorkers
    error("runPaperStudyAssessment:TooManyWorkers", ...
        "NumWorkers cannot exceed the thread pool size of %d.", ...
        pool.NumWorkers);
end
end
